export enum UserRole {
  USER = 'USER',
  DOCTOR = 'DOCTOR',
  ADMIN = 'ADMIN'
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  avatar?: string;
  profile?: HealthProfile;
}

export interface HealthProfile {
  age: number;
  height: number; // cm
  weight: number; // kg
  gender: 'Male' | 'Female' | 'Other';
  bloodType: string;
  allergies: string[];
}

export interface DailyLog {
  date: string;
  steps: number;
  waterIntake: number; // ml
  sleepHours: number;
  mood: 'Happy' | 'Neutral' | 'Stressed' | 'Tired';
  caloriesBurned: number;
  heartRateAvg: number;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

export interface Doctor {
  id: string;
  name: string;
  specialty: string;
  patients: number;
}

import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const createHealthChat = (): Chat => {
  return ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: `You are a Smart Health Assistant. 
      Your goal is to provide general wellness advice, explain medical terms simply, and offer lifestyle tips.

      CRITICAL RULES:
      1. If the user asks for a diagnosis or specific medication, strictly state: "I am an AI assistant, not a doctor. Please consult a healthcare professional for diagnosis and treatment."
      2. Be empathetic, professional, and encouraging.
      3. You support two languages: English and Tamil. If the user asks in Tamil or requests Tamil, reply in Tamil.
      4. Keep answers concise (under 150 words) unless asked for a detailed report.
      `,
    },
  });
};

export const generateHealthReport = async (data: any): Promise<string> => {
  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze this health data and provide a brief summary of risks and 3 recommendations: ${JSON.stringify(data)}`,
    });
    return response.text || "Unable to generate report.";
  } catch (error) {
    console.error("Error generating report:", error);
    return "Error generating report. Please try again later.";
  }
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { User, UserRole } from '../types';

interface AuthContextType {
  user: User | null;
  login: (email: string, role: UserRole) => void;
  logout: () => void;
  isAuthenticated: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

// Mock Users for Demo
const MOCK_USER: User = {
  id: 'u1',
  name: 'Alex Johnson',
  email: 'alex@example.com',
  role: UserRole.USER,
  avatar: 'https://picsum.photos/200',
  profile: {
    age: 24,
    height: 175,
    weight: 70,
    gender: 'Male',
    bloodType: 'O+',
    allergies: ['Peanuts']
  }
};

const MOCK_DOCTOR: User = {
  id: 'd1',
  name: 'Dr. Sarah Smith',
  email: 'sarah@hospital.com',
  role: UserRole.DOCTOR,
  avatar: 'https://picsum.photos/201'
};

const MOCK_ADMIN: User = {
  id: 'a1',
  name: 'System Admin',
  email: 'admin@sys.com',
  role: UserRole.ADMIN,
  avatar: 'https://picsum.photos/202'
};

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    // Check local storage for persisted session
    const storedUser = localStorage.getItem('health_app_user');
    if (storedUser) {
      setUser(JSON.parse(storedUser));
    }
  }, []);

  const login = (email: string, role: UserRole) => {
    let selectedUser = MOCK_USER;
    if (role === UserRole.DOCTOR) selectedUser = MOCK_DOCTOR;
    if (role === UserRole.ADMIN) selectedUser = MOCK_ADMIN;

    // Simulate API delay
    setTimeout(() => {
        const userWithEmail = { ...selectedUser, email };
        setUser(userWithEmail);
        localStorage.setItem('health_app_user', JSON.stringify(userWithEmail));
    }, 500);
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('health_app_user');
  };

  return (
    <AuthContext.Provider value={{ user, login, logout, isAuthenticated: !!user }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

