            <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Role</label>
                <div className="grid grid-cols-3 gap-2">
                    {[UserRole.USER, UserRole.DOCTOR, UserRole.ADMIN].map((r) => (
                        <button
                            key={r}
                            type="button"
                            onClick={() => setRole(r)}
                            className={`py-2 text-xs font-bold uppercase rounded-lg border ${
                                role === r 
                                ? 'bg-teal-50 border-teal-500 text-teal-700' 
                                : 'border-slate-200 text-slate-500 hover:border-teal-300'
                            }`}
                        >
                            {r}
                        </button>
                    ))}
                </div>
            </div>

            <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Email Address</label>
                <input
                    type="email"
                    required
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none transition-all"
                    placeholder="name@example.com"
                />
            </div>

            <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Password</label>
                <input
                    type="password"
                    required
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none transition-all"
                    placeholder="••••••••"
                />
            </div>

            <button
                type="submit"
                disabled={loading}
                className="w-full bg-teal-600 text-white font-bold py-3 rounded-lg hover:bg-teal-700 transition-colors shadow-lg shadow-teal-600/20 disabled:opacity-50"
            >
                {loading ? 'Signing In...' : 'Login'}
            </button>
            </form>

            <div className="mt-6 text-center text-sm text-slate-500">
                <p>Demo Credentials:</p>
                <p>Any email/password works. Select role above.</p>
            </div>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { Login } from './pages/Login';
import { Dashboard } from './pages/Dashboard';
import { Layout } from './components/Layout';
import { AiAssistant } from './components/AiAssistant';
import { Tracker } from './pages/Tracker';
import { Profile } from './pages/Profile';
import { FileText, Download } from 'lucide-react';

// Reports Placeholder Component
const Reports = () => (
    <div className="space-y-6">
        <h1 className="text-2xl font-bold text-slate-800">My Health Reports</h1>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center justify-between">
            <div className="flex items-center">
                <div className="p-4 bg-red-50 rounded-lg mr-4">
                    <FileText className="text-red-500" size={24} />
                </div>
                <div>
                    <h3 className="font-bold text-slate-800">Monthly Comprehensive Report</h3>
                    <p className="text-sm text-slate-500">October 2023 - PDF Analysis</p>
                </div>
            </div>
            <button className="flex items-center text-teal-600 hover:text-teal-700 font-medium">
                <Download size={18} className="mr-2" /> Download
            </button>
        </div>
    </div>
);

// Protected Route Wrapper
const ProtectedRoute = ({ children }: { children: React.ReactNode }) => {
  const { isAuthenticated } = useAuth();
  if (!isAuthenticated) {
    return <Navigate to="/login" replace />;
  }
  return <Layout>{children}</Layout>;
};

const AppContent = () => {
    return (
        <Routes>
            <Route path="/login" element={<Login />} />

            <Route path="/" element={<ProtectedRoute><Dashboard /></ProtectedRoute>} />
            <Route path="/assistant" element={<ProtectedRoute><AiAssistant /></ProtectedRoute>} />
            <Route path="/tracker" element={<ProtectedRoute><Tracker /></ProtectedRoute>} />
            <Route path="/profile" element={<ProtectedRoute><Profile /></ProtectedRoute>} />
            <Route path="/reports" element={<ProtectedRoute><Reports /></ProtectedRoute>} />

            {/* Fallback for other routes */}
            <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
    )
}

function App() {
  return (
    <AuthProvider>
      <HashRouter>
        <AppContent />
      </HashRouter>
    </AuthProvider>
  );
}

export default App;

